// 多次元配列のネスト指定初期化子 (C11 6.7.9): int m[2][2] = {[1][1]=5, [0][1]=3}
// 修正前: 最初の [idx] の後に '=' を期待し、2 つ目の '[' で
//         E2006 "トークンが必要です: '='" となりコンパイル失敗。
// 期待: exit=20  (m[0][1]=3, m[1][1]=5, 残りは 0; 3+5+12)
int main(void) {
  int m[2][2] = {[1][1] = 5, [0][1] = 3};
  return m[0][0] + m[0][1] + m[1][0] + m[1][1] + 12;
}
